class Solution:
    def minimumOperations(self, nums):
        from collections import Counter
        n = len(nums)
        evens = nums[0::2]
        odds = nums[1::2]
        ce = Counter(evens)
        co = Counter(odds)
        candidates = set(ce) | set(co) | {None}
        best = 0
        for a in candidates:
            for b in candidates:
                if a == b:
                    continue
                cnt = (ce.get(a, 0) if a is not None else 0) + (co.get(b, 0) if b is not None else 0)
                if cnt > best:
                    best = cnt
        return n - best

