class Solution:
    def minimumOperations(self, nums):
        from collections import Counter
        n = len(nums)
        evens = nums[0::2]
        odds = nums[1::2]
        ce = Counter(evens).most_common(2)
        co = Counter(odds).most_common(2)
        while len(ce) < 2:
            ce.append((None, 0))
        while len(co) < 2:
            co.append((None, 0))
        if ce[0][0] != co[0][0]:
            keep = ce[0][1] + co[0][1]
        else:
            keep = max(ce[0][1] + co[1][1], ce[1][1] + co[0][1])
        return n - keep

