var minimumOperations = function(nums) {
    const n = nums.length;
    const countTop2 = (arr) => {
        const freq = new Map();
        for (const v of arr) freq.set(v, (freq.get(v) || 0) + 1);
        const entries = [...freq.entries()].sort((a, b) => b[1] - a[1]);
        while (entries.length < 2) entries.push([null, 0]);
        return entries;
    };
    const evens = [];
    const odds = [];
    for (let i = 0; i < n; i++) {
        if (i % 2 === 0) evens.push(nums[i]);
        else odds.push(nums[i]);
    }
    const ce = countTop2(evens);
    const co = countTop2(odds);
    let keep;
    if (ce[0][0] !== co[0][0]) {
        keep = ce[0][1] + co[0][1];
    } else {
        keep = Math.max(ce[0][1] + co[1][1], ce[1][1] + co[0][1]);
    }
    return n - keep;
};
